       `{In O' A} `{forall a, In O (B a)}
  : In O' {x:A & B x}.

Instance inO_sigma (O : Modality)
           {A:Type} (B : A -> Type) `{In O A} `{forall a, In O (B a)}
  : In O {x:A & B x}
  := _.

